screen.userinput:
install -vdm755 /etc/zsh && cat > /etc/zsh/zprofile << "EOF" # Begin /etc/zsh/zprofile # Written for Beyond Linux From Scratch
# System wide environment variables and startup programs.
# Functions to help us manage paths. Second argument is the name of the # path variable to be modified (default: PATH) pathremove () { local IFS=':' local NEWPATH local DIR local PATHVARIABLE=${2:-PATH} for DIR in ${(P)=PATHVARIABLE} ; do if [ "$DIR" != "$1" ] ; then NEWPATH=${NEWPATH:+$NEWPATH:}$DIR fi done export $PATHVARIABLE="$NEWPATH" }
pathprepend () { pathremove $1 $2 local PATHVARIABLE=${2:-PATH} export $PATHVARIABLE="$1${(P)PATHVARIABLE:+:${(P)PATHVARIABLE}}" }
pathappend () { pathremove $1 $2 local PATHVARIABLE=${2:-PATH} export $PATHVARIABLE="${(P)PATHVARIABLE:+${(P)PATHVARIABLE}:}$1" }
# Set the initial path export PATH=/usr/bin
# Attempt to provide backward compatibility with LFS earlier than 11 if [ ! -L /bin ]; then pathappend /bin fi
if [ $EUID -eq 0 ] ; then pathappend /usr/sbin if [ ! -L /sbin ]; then pathappend /sbin fi unset HISTFILE fi
# Set some defaults for graphical systems export XDG_DATA_DIRS=${XDG_DATA_DIRS:-/usr/share} export XDG_CONFIG_DIRS=${XDG_CONFIG_DIRS:-/etc/xdg} export XDG_RUNTIME_DIR=${XDG_RUNTIME_DIR:-/tmp/xdg-$USER}
for script in /etc/profile.d/*.sh ; do if [ -r $script ] ; then . $script fi done
unset script
# End /etc/zsh/zprofile EOF
